from dataclasses import dataclass
from typing import List

@dataclass
class FunctionDescriptor:
    name: str
    parameters: List[str]

def evaluate_function(descriptor: FunctionDescriptor, args: List[str]) -> str:
    if descriptor.name == "concat":
        return concat_function(args)
    elif descriptor.name == "sum":
        return sum_function(args)
    else:
        raise ValueError("Unknown function")

def concat_function(args: List[str]) -> str:
    return ''.join(args)

def sum_function(args: List[str]) -> str:
    total = sum(int(arg) for arg in args)
    return str(total)

def main():
    descriptor = FunctionDescriptor(name="concat", parameters=["arg1", "arg2"])
    result = evaluate_function(descriptor, ["Hello, ", "World!"])
    print(result)

    descriptor = FunctionDescriptor(name="sum", parameters=["arg1", "arg2"])
    result = evaluate_function(descriptor, ["10", "20"])
    print(result)

if __name__ == "__main__":
    main()
